import{c as s,Q as e,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"容器格式:MP4 / FLV / MKV / WebM","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/04-容器格式-MP4-FLV-MKV-WebM.md","filePath":"mediaTechLearning/04-容器格式-MP4-FLV-MKV-WebM.md","lastUpdated":1780887690000}'),p={name:"mediaTechLearning/04-容器格式-MP4-FLV-MKV-WebM.md"};function n(l,a,h,o,d,c){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="容器格式-mp4-flv-mkv-webm" tabindex="-1">容器格式:MP4 / FLV / MKV / WebM <a class="header-anchor" href="#容器格式-mp4-flv-mkv-webm" aria-label="Permalink to &quot;容器格式:MP4 / FLV / MKV / WebM&quot;">​</a></h1><p>容器不是编码。容器解决的是:<strong>把多条流和它们的时间关系装在一个文件里</strong>。</p><blockquote><p>一句话先记住:<strong>容器管&quot;怎么装&quot;,编码管&quot;怎么压&quot;</strong>。排查播放兼容性时,永远分两步:先看容器,再看里面的编码。</p></blockquote><hr><h2 id="一、容器里装什么" tabindex="-1">一、容器里装什么 <a class="header-anchor" href="#一、容器里装什么" aria-label="Permalink to &quot;一、容器里装什么&quot;">​</a></h2><p>一个视频文件通常不是一条流:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>container</span></span>
<span class="line"><span>  video stream: H.264 / H.265 / VP9 / AV1</span></span>
<span class="line"><span>  audio stream: AAC / Opus / MP3</span></span>
<span class="line"><span>  subtitle stream</span></span>
<span class="line"><span>  metadata</span></span>
<span class="line"><span>  timestamps</span></span></code></pre></div><p>查看:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -hide_banner</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffprobe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -show_streams</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span></span></code></pre></div><p>看到 <code>codec_name=h264</code> 不代表容器是 H.264,只代表视频流编码是 H.264。</p><hr><h2 id="二、mp4-最常见-但不是万能" tabindex="-1">二、MP4:最常见,但不是万能 <a class="header-anchor" href="#二、mp4-最常见-但不是万能" aria-label="Permalink to &quot;二、MP4:最常见,但不是万能&quot;">​</a></h2><p>MP4 适合点播、移动端、浏览器播放。常见组合:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MP4 + H.264 + AAC</span></span>
<span class="line"><span>MP4 + H.265 + AAC</span></span></code></pre></div><p>兼容性最稳的是 H.264 + AAC。H.265 在很多设备上能播,但浏览器支持受平台和授权影响,不能只看后缀。</p><p>MP4 还有一个关键点:<code>moov atom</code>。它保存索引信息。普通 MP4 如果 <code>moov</code> 在文件尾,浏览器要等下载到尾部才知道怎么播。优化:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mp4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -movflags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +faststart</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p>这会把 <code>moov</code> 挪到文件头,适合网页渐进播放。</p><hr><h2 id="三、flv-直播老兵" tabindex="-1">三、FLV:直播老兵 <a class="header-anchor" href="#三、flv-直播老兵" aria-label="Permalink to &quot;三、FLV:直播老兵&quot;">​</a></h2><p>FLV 常见于老直播链路:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RTMP 推流 -&gt; FLV 播放</span></span></code></pre></div><p>优点:</p><ul><li>结构简单</li><li>延迟比 HLS 低</li><li>历史生态多</li></ul><p>缺点:</p><ul><li>浏览器原生不直接支持 FLV</li><li>通常需要 flv.js 这类 MSE 播放器</li><li>移动端和现代浏览器生态不如 HLS / WebRTC</li></ul><p>FLV 不是未来主线,但很多直播系统还会遇到。</p><hr><h2 id="四、mkv-能装-但不适合-web-默认分发" tabindex="-1">四、MKV:能装,但不适合 Web 默认分发 <a class="header-anchor" href="#四、mkv-能装-但不适合-web-默认分发" aria-label="Permalink to &quot;四、MKV:能装,但不适合 Web 默认分发&quot;">​</a></h2><p>MKV 很灵活,什么都能装:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MKV + H.264 + AAC</span></span>
<span class="line"><span>MKV + H.265 + Opus</span></span>
<span class="line"><span>MKV + 多字幕 / 多音轨</span></span></code></pre></div><p>它适合本地收藏、影视文件、复杂字幕音轨。但 Web 分发不要默认选 MKV。浏览器、移动端、硬件播放器兼容性会让你付代价。</p><hr><h2 id="五、webm-web-友好但生态分裂" tabindex="-1">五、WebM:Web 友好但生态分裂 <a class="header-anchor" href="#五、webm-web-友好但生态分裂" aria-label="Permalink to &quot;五、WebM:Web 友好但生态分裂&quot;">​</a></h2><p>WebM 常见组合:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebM + VP9 + Opus</span></span>
<span class="line"><span>WebM + AV1 + Opus</span></span></code></pre></div><p>适合浏览器和开放编码生态,但在部分平台、硬件解码、编辑工具链上不如 MP4/H.264 普遍。</p><p>WebM 经常出现在 MediaRecorder 默认输出里。你录出来的是 WebM,不等于后端、移动端、剪辑工具都能顺利处理。</p><hr><h2 id="六、转封装-不重新压缩" tabindex="-1">六、转封装:不重新压缩 <a class="header-anchor" href="#六、转封装-不重新压缩" aria-label="Permalink to &quot;六、转封装:不重新压缩&quot;">​</a></h2><p>容器换掉,编码不变:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ffmpeg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> input.mkv</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> copy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> output.mp4</span></span></code></pre></div><p><code>-c copy</code> 表示直接复制流。快,损失小。但前提是目标容器能装这些编码。比如 MP4 不适合装某些字幕或音频编码,命令会失败或产出兼容性差的文件。</p><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>后缀不可信</strong>——<code>.mp4</code> 里可能是浏览器不支持的编码。</li><li><strong>转封装不是转码</strong>——<code>-c copy</code> 不会改变编码兼容性。</li><li><strong>Web 默认 H.264 + AAC 最稳</strong>——追新编码前先看目标设备。</li><li><strong>MP4 网页播放记得 faststart</strong>。</li><li><strong>MediaRecorder 输出要检查 MIME</strong>——不要假设录出来就是 MP4。</li></ol><p>下一篇:<code>05-编码格式:H.264 / H.265 / VP9 / AV1 / AAC / Opus.md</code>。</p>`,47)])])}const b=s(p,[["render",n]]);export{k as __pageData,b as default};
